package firstProjecct;

public class Increments {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		
		int x = 10;
//		int y = x++;
		int y = x--;
		
		System.out.println(y);
		System.out.println(x);
		System.out.println();

		int k = 10;
		int l = ++k;
		
		System.out.println(l);
		System.out.println(k);


	}

}
